        main_frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)
        
        # Left panel - Controls
        control_frame = ttk.LabelFrame(main_frame, text="Zone Controls", padding=10)
        control_frame.pack(side=tk.LEFT, fill=tk.Y, padx=(0, 10))
        
        # Template selection
        ttk.Label(control_frame, text="Maze Template:").pack(anchor=tk.W, pady=(0, 5))
        current_maze = self.main_app.params['maze_type']
        template_values = list(self.main_app.zone_templates.keys()) + ['Custom Arena']
        self.template_var = tk.StringVar(value=current_maze if current_maze in template_values else 'Custom Arena')
        template_combo = ttk.Combobox(control_frame, textvariable=self.template_var,
                                     values=template_values,
                                     state='readonly', width=20)
        template_combo.pack(fill=tk.X, pady=(0, 5))
        template_combo.bind('<<ComboboxSelected>>', self.load_template)

        # Maze width (editable; always shown so users can adjust)
        maze_width_frame = ttk.Frame(control_frame)
        maze_width_frame.pack(fill=tk.X, pady=(0, 10))
        ttk.Label(maze_width_frame, text="Arena Width (cm):").pack(side=tk.LEFT)
        self.maze_width_var = tk.StringVar(value=str(self.maze_width))
        maze_width_entry = ttk.Entry(maze_width_frame, textvariable=self.maze_width_var, width=8)
        maze_width_entry.pack(side=tk.LEFT, padx=5)
        ttk.Button(maze_width_frame, text="Apply", width=6,
                   command=self._apply_maze_width).pack(side=tk.LEFT)
        
        ttk.Separator(control_frame, orient=tk.HORIZONTAL).pack(fill=tk.X, pady=10)
        
        # Zone list
        ttk.Label(control_frame, text="Zones:").pack(anchor=tk.W, pady=(0, 5))
        
        zone_list_frame = ttk.Frame(control_frame)
        zone_list_frame.pack(fill=tk.BOTH, expand=True, pady=(0, 10))
        
        scrollbar = ttk.Scrollbar(zone_list_frame)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        
        self.zone_listbox = tk.Listbox(zone_list_frame, yscrollcommand=scrollbar.set,
                                       height=15, width=25)
        self.zone_listbox.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        scrollbar.config(command=self.zone_listbox.yview)
        self.zone_listbox.bind('<<ListboxSelect>>', self.select_zone_from_list)
        
        self.populate_zone_list()

        # Zone management buttons (for custom arena)
        zone_mgmt_frame = ttk.Frame(control_frame)
        zone_mgmt_frame.pack(fill=tk.X, pady=(0, 5))
        ttk.Button(zone_mgmt_frame, text="+ Add Zone",
                   command=self.add_zone).pack(side=tk.LEFT, padx=(0, 3))
        ttk.Button(zone_mgmt_frame, text="- Remove",
                   command=self.remove_zone).pack(side=tk.LEFT, padx=(0, 3))
        ttk.Button(zone_mgmt_frame, text="Rename",
                   command=self.rename_zone).pack(side=tk.LEFT)
        
        # Zone details
        ttk.Separator(control_frame, orient=tk.HORIZONTAL).pack(fill=tk.X, pady=10)
        ttk.Label(control_frame, text="Selected Zone Details:").pack(anchor=tk.W, pady=(0, 5))
        
        details_frame = ttk.Frame(control_frame)
        details_frame.pack(fill=tk.X, pady=(0, 10))
        
        ttk.Label(details_frame, text="X Min:").grid(row=0, column=0, sticky=tk.W, pady=2)
        self.x_min_var = tk.StringVar()
        self.x_min_entry = ttk.Entry(details_frame, textvariable=self.x_min_var, width=10)
        self.x_min_entry.grid(row=0, column=1, padx=5, pady=2)
        
        ttk.Label(details_frame, text="X Max:").grid(row=1, column=0, sticky=tk.W, pady=2)
        self.x_max_var = tk.StringVar()
        self.x_max_entry = ttk.Entry(details_frame, textvariable=self.x_max_var, width=10)
        self.x_max_entry.grid(row=1, column=1, padx=5, pady=2)
        
        ttk.Label(details_frame, text="Y Min:").grid(row=2, column=0, sticky=tk.W, pady=2)
        self.y_min_var = tk.StringVar()
        self.y_min_entry = ttk.Entry(details_frame, textvariable=self.y_min_var, width=10)
        self.y_min_entry.grid(row=2, column=1, padx=5, pady=2)
        
        ttk.Label(details_frame, text="Y Max:").grid(row=3, column=0, sticky=tk.W, pady=2)
        self.y_max_var = tk.StringVar()
        self.y_max_entry = ttk.Entry(details_frame, textvariable=self.y_max_var, width=10)
        self.y_max_entry.grid(row=3, column=1, padx=5, pady=2)

        ttk.Label(details_frame, text="Category:").grid(row=4, column=0, sticky=tk.W, pady=2)
