    def update_conn_listbox(self):
        """Update listbox based on analysis mode"""
        self.conn_listbox.delete(0, 'end')
        if self.conn_mode_var.get() == 'Subject':
            for subject in sorted(self.processed_data.keys()):
                self.conn_listbox.insert('end', subject)
        else:  # Group
            for group in sorted(self.groups.keys()):
                self.conn_listbox.insert('end', group)

    def _toggle_grp_tab_mode(self):
        """Show/hide By-Bout-specific fields and buttons in the By Group tab."""
        mode = self._grp_tab_mode_var.get()
        if mode == "By Bout":
            self._grp_bout_params_row.grid()
            self._grp_ws_btns.grid_remove()
            self._grp_bout_btns.grid()
        else:
            self._grp_bout_params_row.grid_remove()
            self._grp_bout_btns.grid_remove()
            self._grp_ws_btns.grid()

    # ------------------------------------------------------------------ #
    #  Auto-Tune Coherence Settings                                        #
    # ------------------------------------------------------------------ #

    def auto_tune_coherence_settings(self):
        """
        Automatically tests Morlet and Welch parameter combinations on the
        first available subject pair and scores each by spectral structure
        (dynamic range × spectral variance, penalising ceiling/floor effects).
        Opens a results window with a preview plot and Apply buttons.
        """
        if not self.processed_data:
            messagebox.showwarning("No Data",
                "Process at least one subject before running Auto-Tune.")
            return

        ch1 = self.conn_channel1_var.get()
        ch2 = self.conn_channel2_var.get()

        # Find first subject with both channels
        sig1 = sig2 = fs = subj_id = None
        for sid, data in self.processed_data.items():
            try:
                s1 = self._get_channel_signal(data, ch1)
                s2 = self._get_channel_signal(data, ch2)
                if s1 is not None and s2 is not None and len(s1) > 200:
                    sig1, sig2 = s1, s2
                    fs = float(data.get('photometry_fps') or 20.0)
                    subj_id = sid
                    break
            except Exception:
                continue

        if sig1 is None:
            messagebox.showwarning("No Data",
                f"Could not find valid signals for channels {ch1}/{ch2}.")
            return

        fmin = self.conn_params.get('static_fmin', 0.05)
        fmax = self.conn_params.get('static_fmax', 10.0)

        def _score(freqs, coh, fmin, fmax):
            mask = (freqs >= fmin) & (freqs <= fmax)
            if not np.any(mask):
                return 0.0
            c = coh[mask]
            dyn   = float(np.max(c) - np.min(c))
            var   = float(np.var(c))
            mean  = float(np.mean(c))
            # Penalise ceiling (>0.8) and floor (<0.05)
            ceiling = float(np.mean(c > 0.8)) * 0.5
            floor_p = float(np.mean(c < 0.05)) * 0.3
            return max(0.0, dyn * 0.5 + var * 3.0 - ceiling - floor_p)

        configs = []
        # Morlet combinations
        for w in [4, 5, 6, 7, 8]:
            for n in [30, 50, 75, 100]:
                configs.append(('Morlet Wavelet', {'morlet_w': w, 'morlet_n_freqs': n}))
        # Welch combinations
        for win in [5, 10, 20, 40, 60]:
            configs.append(('Welch', {'nperseg_sec': win}))

        results = []

        def _worker(q):
            total = len(configs)
            for i, (method, cfg) in enumerate(configs):
                q.put(('status', f"Testing {method} ({i+1}/{total})…"))
                try:
                    if method == 'Morlet Wavelet':
                        r = self.calculate_static_coherence_morlet(
                            sig1, sig2, fs, fmin=fmin, fmax=fmax,
                            n_freqs=cfg['morlet_n_freqs'], w=cfg['morlet_w'])
                    else:
                        r = self.calculate_static_coherence(
                            sig1, sig2, fs, fmin=fmin, fmax=fmax,
                            nperseg=cfg['nperseg_sec'])
                    if r is not None:
                        sc = _score(r['freqs'], r['coh'], fmin, fmax)
                        results.append({
                            'method': method, 'config': cfg,
                            'score': sc,
                            'freqs': r['freqs'], 'coh': r['coh'],
                            'mean_coh': float(np.mean(r['coh'])),
                        })
                except Exception:
                    pass
            q.put(('done', results))

        def _on_done():
            if not results:
                messagebox.showerror("Auto-Tune", "No parameter set produced valid results.")
                return
            results.sort(key=lambda x: x['score'], reverse=True)
            self._show_autotune_results(results, subj_id, fmin, fmax)

        self._run_with_progress("Auto-Tune Coherence Settings", _worker, _on_done)

    def _show_autotune_results(self, results, subj_id, fmin, fmax):
        """Display Auto-Tune results in a window with table + preview plot."""
        win = tk.Toplevel(self.root)
        win.title("Auto-Tune Results")
        win.geometry("1050x680")
        win.transient(self.root)

        # Split: left = table, right = plot
        paned = ttk.PanedWindow(win, orient='horizontal')
        paned.pack(fill='both', expand=True, padx=8, pady=8)

        # ── Left: results table ───────────────────────────────────────────
        left = ttk.Frame(paned, padding=4)
        paned.add(left, weight=1)

        ttk.Label(left,
                  text=f"Parameter sweep results for subject: {subj_id}\n"
                       f"Scored by spectral structure ({fmin}–{fmax} Hz).\n"
                       f"Higher score = more frequency-specific coherence structure.",
                  foreground='gray', font=('Segoe UI', 8),
                  wraplength=380, justify='left').pack(anchor='w', pady=(0, 6))

        cols = ('Rank', 'Method', 'Parameters', 'Score', 'Mean Coh')
        tree = ttk.Treeview(left, columns=cols, show='headings', height=20,
                            selectmode='browse')
        for col, w in zip(cols, [40, 120, 200, 60, 70]):
            tree.heading(col, text=col)
            tree.column(col, width=w, anchor='center')

        # Colour top 3 Morlet and top 3 Welch
        tree.tag_configure('top_morlet', background='#d4ecd4')
        tree.tag_configure('top_welch',  background='#d4d4ec')

        morlet_count = welch_count = 0
        for rank, r in enumerate(results, 1):
            m = r['method']
            cfg = r['config']
            if m == 'Morlet Wavelet':
                param_str = f"w={cfg['morlet_w']}, n={cfg['morlet_n_freqs']}"
                tag = 'top_morlet' if morlet_count < 3 else ''
                morlet_count += 1
            else:
                param_str = f"window={cfg['nperseg_sec']}s"
                tag = 'top_welch' if welch_count < 3 else ''
                welch_count += 1
            tree.insert('', 'end', iid=str(rank),
                        values=(rank, m, param_str,
                                f"{r['score']:.4f}",
                                f"{r['mean_coh']:.3f}"),
                        tags=(tag,))

        tsb = ttk.Scrollbar(left, orient='vertical', command=tree.yview)
        tree.configure(yscrollcommand=tsb.set)
        tree.pack(side='left', fill='both', expand=True)
        tsb.pack(side='right', fill='y')

        # ── Apply buttons ─────────────────────────────────────────────────
        btn_row = ttk.Frame(win)
        btn_row.pack(fill='x', padx=8, pady=(0, 6))

        # Best Morlet
        best_morlet = next((r for r in results if r['method'] == 'Morlet Wavelet'), None)
        # Best Welch
        best_welch  = next((r for r in results if r['method'] == 'Welch'), None)

        def _apply(r):
            cfg = r['config']
            if r['method'] == 'Morlet Wavelet':
                self.conn_params['morlet_w'] = cfg['morlet_w']
                self.conn_params['morlet_n_freqs'] = cfg['morlet_n_freqs']
                self.conn_params['coherence_method'] = 'Morlet Wavelet'
                self.conn_coh_method_var.set('Morlet Wavelet')
                self.log_message(
                    f"Auto-Tune applied: Morlet w={cfg['morlet_w']}, "
                    f"n_freqs={cfg['morlet_n_freqs']}")
            else:
                self.conn_params['static_nperseg_sec'] = cfg['nperseg_sec']
                self.conn_params['coherence_method'] = 'Welch'
                self.conn_coh_method_var.set('Welch')
                self.log_message(
                    f"Auto-Tune applied: Welch window={cfg['nperseg_sec']}s")
            messagebox.showinfo("Applied", "Settings updated.", parent=win)

        if best_morlet:
            cfg = best_morlet['config']
            ttk.Button(btn_row,
                       text=f"Apply Best Morlet  (w={cfg['morlet_w']}, n={cfg['morlet_n_freqs']})",
                       command=lambda r=best_morlet: _apply(r)
                       ).pack(side='left', padx=6)
        if best_welch:
            cfg = best_welch['config']
            ttk.Button(btn_row,
                       text=f"Apply Best Welch  (window={cfg['nperseg_sec']}s)",
                       command=lambda r=best_welch: _apply(r)
                       ).pack(side='left', padx=6)

        def _apply_selected():
            sel = tree.selection()
            if not sel:
                messagebox.showwarning("Select", "Select a row first.", parent=win)
                return
            rank = int(sel[0]) - 1
            _apply(results[rank])

        ttk.Button(btn_row, text="Apply Selected Row",
                   command=_apply_selected).pack(side='left', padx=6)
        ttk.Button(btn_row, text="Close", command=win.destroy).pack(side='right', padx=6)

        # ── Right: preview plot (top 5) ───────────────────────────────────
        right = ttk.Frame(paned, padding=4)
        paned.add(right, weight=2)

        ttk.Label(right, text="Coherence spectra — top 5 configurations",
                  font=('Segoe UI', 9, 'bold')).pack(anchor='w')

        fig = Figure(figsize=(6, 4.5), dpi=96)
        ax  = fig.add_subplot(111)

        palette = ['#1f77b4','#d62728','#2ca02c','#ff7f0e','#9467bd']
        for i, r in enumerate(results[:5]):
            cfg = r['config']
            if r['method'] == 'Morlet Wavelet':
                lbl = f"Morlet w={cfg['morlet_w']},n={cfg['morlet_n_freqs']}  (score={r['score']:.3f})"
            else:
                lbl = f"Welch win={cfg['nperseg_sec']}s  (score={r['score']:.3f})"
            ax.plot(r['freqs'], r['coh'], color=palette[i], lw=1.5, label=lbl, alpha=0.85)

        ax.set_xlabel("Frequency (Hz)")
        ax.set_ylabel("Coherence")
        ax.set_title(f"Top 5 parameter sets  ·  {subj_id}  ·  {ch1}–{ch2}")
        ax.legend(fontsize=7, loc='upper right')
        ax.set_xlim(fmin, fmax)
        ax.set_ylim(0, 1)
        fig.tight_layout()

        cv2 = FigureCanvasTkAgg(fig, master=right)
        NavigationToolbar2Tk(cv2, right)
        cv2.get_tk_widget().pack(fill='both', expand=True)
        cv2.draw()

        # Click row → highlight spectrum
        def _on_select(event):
            sel = tree.selection()
            if not sel:
                return
            rank = int(sel[0]) - 1
            r = results[rank]
            cfg = r['config']
            ax.clear()
            # Redraw all top-5 faded
            for i, ri in enumerate(results[:5]):
                ax.plot(ri['freqs'], ri['coh'], color=palette[i], lw=1, alpha=0.3)
            # Highlight selected
            ax.plot(r['freqs'], r['coh'], color='black', lw=2.5,
                    label=('Morlet w={morlet_w},n={morlet_n_freqs}'.format(**cfg)
                           if r['method'] == 'Morlet Wavelet'
                           else f"Welch win={cfg['nperseg_sec']}s"))
            ax.set_xlabel("Frequency (Hz)")
            ax.set_ylabel("Coherence")
            ax.set_title(f"Selected: rank {rank+1}  ·  score={r['score']:.4f}")
            ax.set_xlim(fmin, fmax); ax.set_ylim(0, 1)
            ax.legend(fontsize=8)
            fig.tight_layout()
            cv2.draw()

        tree.bind('<<TreeviewSelect>>', _on_select)

    # ------------------------------------------------------------------ #
    #  Frequency Band Manager                                              #
    # ------------------------------------------------------------------ #

    def _refresh_freq_band_listbox(self):
        """Repopulate the frequency bands listbox from conn_params."""
        if not hasattr(self, 'freq_bands_listbox'):
            return
        self.freq_bands_listbox.delete(0, 'end')
        for b in self.conn_params.get('freq_bands', []):
            self.freq_bands_listbox.insert(
                'end',
                f"  {b['name']:<16}  {b['fmin']:.3f} – {b['fmax']:.3f} Hz")

    def _freq_band_dialog(self, title, name='', fmin='', fmax=''):
        """Open a dialog to enter/edit one frequency band. Returns (name, fmin, fmax) or None."""
        result = {'value': None}
        dlg = tk.Toplevel(self.root)
        dlg.title(title)
        dlg.geometry("320x180")
        dlg.resizable(False, False)
        dlg.transient(self.root)
        dlg.grab_set()

        frm = ttk.Frame(dlg, padding=16)
        frm.pack(fill='both', expand=True)

        ttk.Label(frm, text="Band name:").grid(row=0, column=0, sticky='w', pady=4)
        name_var = tk.StringVar(value=name)
        ttk.Entry(frm, textvariable=name_var, width=20).grid(row=0, column=1, padx=6, pady=4)

        ttk.Label(frm, text="Min frequency (Hz):").grid(row=1, column=0, sticky='w', pady=4)
        fmin_var = tk.StringVar(value=str(fmin))
        ttk.Entry(frm, textvariable=fmin_var, width=12).grid(row=1, column=1, padx=6, pady=4)

        ttk.Label(frm, text="Max frequency (Hz):").grid(row=2, column=0, sticky='w', pady=4)
        fmax_var = tk.StringVar(value=str(fmax))
        ttk.Entry(frm, textvariable=fmax_var, width=12).grid(row=2, column=1, padx=6, pady=4)

        def _ok():
            n = name_var.get().strip()
            if not n:
                messagebox.showerror("Invalid", "Band name cannot be empty.", parent=dlg)
                return
            try:
                lo = float(fmin_var.get())
                hi = float(fmax_var.get())
            except ValueError:
                messagebox.showerror("Invalid", "Frequencies must be numbers.", parent=dlg)
                return
            if lo >= hi:
                messagebox.showerror("Invalid", "Min must be less than Max.", parent=dlg)
                return
            result['value'] = {'name': n, 'fmin': lo, 'fmax': hi}
            dlg.destroy()

        btn_row = ttk.Frame(frm)
        btn_row.grid(row=3, column=0, columnspan=2, pady=(10, 0))
        ttk.Button(btn_row, text="OK", command=_ok).pack(side='left', padx=6)
        ttk.Button(btn_row, text="Cancel", command=dlg.destroy).pack(side='left', padx=6)
        dlg.wait_window()
        return result['value']

    def _freq_band_add(self):
        band = self._freq_band_dialog("Add Frequency Band")
        if band:
            self.conn_params['freq_bands'].append(band)
            self._refresh_freq_band_listbox()

    def _freq_band_edit(self):
        sel = self.freq_bands_listbox.curselection()
        if not sel:
            messagebox.showwarning("No Selection", "Select a band to edit.", parent=self.root)
            return
        idx = sel[0]
        old = self.conn_params['freq_bands'][idx]
        band = self._freq_band_dialog("Edit Frequency Band",
                                      name=old['name'], fmin=old['fmin'], fmax=old['fmax'])
        if band:
            self.conn_params['freq_bands'][idx] = band
            self._refresh_freq_band_listbox()

    def _freq_band_remove(self):
        sel = self.freq_bands_listbox.curselection()
        if not sel:
            messagebox.showwarning("No Selection", "Select a band to remove.", parent=self.root)
            return
        idx = sel[0]
        name = self.conn_params['freq_bands'][idx]['name']
        if messagebox.askyesno("Confirm", f"Remove band '{name}'?", parent=self.root):
            self.conn_params['freq_bands'].pop(idx)
            self._refresh_freq_band_listbox()

    def _freq_band_move(self, direction):
        """Move selected band up (-1) or down (+1)."""
        sel = self.freq_bands_listbox.curselection()
        if not sel:
            return
        idx = sel[0]
        bands = self.conn_params['freq_bands']
        new_idx = idx + direction
        if new_idx < 0 or new_idx >= len(bands):
            return
        bands[idx], bands[new_idx] = bands[new_idx], bands[idx]
        self._refresh_freq_band_listbox()
        self.freq_bands_listbox.selection_set(new_idx)

    def _freq_band_reset_defaults(self):
        self.conn_params['freq_bands'] = [
            {'name': 'Infra-slow', 'fmin': 0.05, 'fmax': 0.5},
            {'name': 'Slow',       'fmin': 0.5,  'fmax': 1.0},
            {'name': 'Delta',      'fmin': 1.0,  'fmax': 4.0},
            {'name': 'Theta',      'fmin': 4.0,  'fmax': 8.0},
            {'name': 'High',       'fmin': 8.0,  'fmax': 12.0},
        ]
        self._refresh_freq_band_listbox()

    def _get_active_freq_bands(self):
        """Return the active frequency bands, falling back to defaults if empty."""
        bands = self.conn_params.get('freq_bands', [])
        if not bands:
            bands = [
                {'name': 'Infra-slow', 'fmin': 0.05, 'fmax': 0.5},
                {'name': 'Slow',       'fmin': 0.5,  'fmax': 1.0},
                {'name': 'Delta',      'fmin': 1.0,  'fmax': 4.0},
                {'name': 'Theta',      'fmin': 4.0,  'fmax': 8.0},
                {'name': 'High',       'fmin': 8.0,  'fmax': 12.0},
            ]
        return bands

    def _band_mean_from_spectrum(self, freqs, coh, band):
        """Return mean coherence within a band's frequency range."""
        mask = (freqs >= band['fmin']) & (freqs <= band['fmax'])
        if not np.any(mask):
            return np.nan
        return float(np.nanmean(coh[mask]))

    # ------------------------------------------------------------------ #
    #  Group Coherence Comparison helpers                                  #
    # ------------------------------------------------------------------ #

    def _refresh_grp_comp_listbox(self):
        """Populate the group comparison listbox from self.groups."""
        if not hasattr(self, 'grp_comp_listbox'):
            return
        self.grp_comp_listbox.delete(0, 'end')
        for g in sorted(self.groups.keys()):
            n = len(self.groups[g])
            self.grp_comp_listbox.insert('end', f"{g}  (n={n})")

    def run_group_coherence_comparison(self):
        """Compute per-subject static coherence for each selected group and store results."""
        sel = self.grp_comp_listbox.curselection()
        if not sel:
            messagebox.showwarning("No Groups",
                "Select two or more groups from the comparison list.\n"
                "Click '↺ Refresh Groups' if the list is empty.")
            return
        if not self.processed_data:
            messagebox.showwarning("No Data", "No processed subjects found.")
            return

        # Parse group names (strip the (n=X) suffix we added)
        raw_names = [self.grp_comp_listbox.get(i) for i in sel]
        selected_groups = [n.rsplit('  (n=', 1)[0].strip() for n in raw_names]

        if len(selected_groups) < 2:
            messagebox.showwarning("Too Few Groups",
                "Select at least two groups to compare.")
            return

        ch1 = self.conn_channel1_var.get()
        ch2 = self.conn_channel2_var.get()
        if ch1 == ch2:
            messagebox.showwarning("Invalid Channels",
                "Please select two different channels.")
            return

        use_excl = self.use_exclusions_conn.get()
        fs = float(self.params.get('fps', 30))
        fmin = self.conn_params['static_fmin']
        fmax = self.conn_params['static_fmax']
        nperseg_sec = self.conn_params['static_nperseg_sec']
        method = self.conn_params.get('coherence_method', 'Welch')
        morlet_n = int(self.conn_params.get('morlet_n_freqs', 50))
        morlet_w = float(self.conn_params.get('morlet_w', 6.0))
        bands = self._get_active_freq_bands()

        self.group_coherence_results = {}
        total_subjects = sum(len(self.groups.get(g, [])) for g in selected_groups)
        _pd = self.processed_data
        _groups = self.groups
        _params = dict(self.conn_params)

        def _worker(q):
            done = 0
            for gname in selected_groups:
                members = _groups.get(gname, [])
                group_entry = {
                    'group': gname,
                    'ch1': ch1, 'ch2': ch2,
                    'method': method,
                    'fmin': fmin, 'fmax': fmax,
                    'subjects': {},   # subject -> {'freqs', 'coh', 'band_means'}
                }
                for subj in members:
                    done += 1
                    q.put(('status', f"Group '{gname}' — {subj}  ({done}/{total_subjects})"))
                    if subj not in _pd:
                        continue
                    if use_excl:
                        if self.is_subject_channel_excluded(subj, ch1) or \
                           self.is_subject_channel_excluded(subj, ch2):
                            q.put(('log', f"  Skipping {subj}: channel excluded"))
                            continue
                    data = _pd[subj]
                    s1 = self._get_channel_signal(data, ch1)
                    s2 = self._get_channel_signal(data, ch2)
                    if s1 is None or s2 is None:
                        q.put(('log', f"  Skipping {subj}: channel data missing"))
                        continue
                    if method == 'Morlet Wavelet':
                        res = self.calculate_static_coherence_morlet(
                            s1, s2, fs=fs, fmin=fmin, fmax=fmax,
                            n_freqs=morlet_n, w=morlet_w)
                    else:
                        res = self.calculate_static_coherence(
                            s1, s2, fs=fs, fmin=fmin, fmax=fmax,
                            nperseg=nperseg_sec)
                    if res is None:
                        q.put(('log', f"  Could not compute coherence for {subj}"))
                        continue
                    freqs = np.asarray(res['freqs'])
                    coh = np.asarray(res['coh'])
                    bm = {b['name']: self._band_mean_from_spectrum(freqs, coh, b)
                          for b in bands}
                    group_entry['subjects'][subj] = {
                        'freqs': freqs, 'coh': coh, 'band_means': bm
                    }
                    q.put(('log',
                           f"  {subj}: mean coherence = {float(np.nanmean(coh)):.4f}"))

                if group_entry['subjects']:
                    self.group_coherence_results[gname] = group_entry
                    n_ok = len(group_entry['subjects'])
                    q.put(('log',
                           f"Group '{gname}': {n_ok}/{len(members)} subjects processed."))

        def _on_done():
            n_grp = len(self.group_coherence_results)
            msg = (f"{n_grp} group(s) processed.  "
                   f"Click 'Plot Spectra Comparison' or 'Plot Band Comparison' to visualize.")
            self.grp_comp_status_var.set(msg)
            self.log_message(f"Group coherence comparison complete — {n_grp} group(s).")
            if not self.group_coherence_results:
                messagebox.showwarning("No Results",
                    "No subjects could be processed. Check that groups are defined "
                    "and subjects have been processed.")

        self._run_with_progress(
            "Running Group Coherence Comparison…", _worker, _on_done)

    # ── Palette helper ─────────────────────────────────────────────────────
    _GRP_PALETTE = [
        '#1f77b4', '#d62728', '#2ca02c', '#ff7f0e',
        '#9467bd', '#8c564b', '#e377c2', '#17becf',
        '#bcbd22', '#7f7f7f',
    ]

    def visualize_group_coherence_spectra(self):
        """Plot group mean ± SEM coherence spectra, one line per group."""
        if not self.group_coherence_results:
            messagebox.showwarning("No Data",
                "Run '▶ Run Group Comparison' first.")
            return

        results = self.group_coherence_results
        show_traces = self.grp_comp_show_traces_var.get()
        fmin = float(self.conn_params.get('freq_xmin', 0))
        fmax = float(self.conn_params.get('freq_xmax', 10))
        ymin = float(self.conn_params.get('coh_ymin', 0))
        ymax = float(self.conn_params.get('coh_ymax', 1))
        bands = self._get_active_freq_bands()

        # Build figure
        fig, ax = plt.subplots(figsize=(10, 5))

        for gi, (gname, gdata) in enumerate(results.items()):
            color = self._GRP_PALETTE[gi % len(self._GRP_PALETTE)]
            subjects = gdata['subjects']
            if not subjects:
                continue

            # Collect all spectra, interpolating onto a common grid
            ref_freqs = next(iter(subjects.values()))['freqs']
            coh_stack = []
            for sdata in subjects.values():
                if len(sdata['freqs']) == len(ref_freqs) and np.allclose(sdata['freqs'], ref_freqs):
                    coh_stack.append(sdata['coh'])
                else:
                    coh_stack.append(np.interp(ref_freqs, sdata['freqs'], sdata['coh']))
            coh_arr = np.vstack(coh_stack)
            n = coh_arr.shape[0]
            mean_coh = np.nanmean(coh_arr, axis=0)
            sem_coh = np.nanstd(coh_arr, axis=0, ddof=1) / np.sqrt(n) if n > 1 else np.zeros_like(mean_coh)

            if show_traces:
                for row in coh_arr:
                    ax.plot(ref_freqs, row, color=color, lw=0.6, alpha=0.3)

            ax.plot(ref_freqs, mean_coh, color=color, lw=2.2,
                    label=f"{gname} (n={n})")
            ax.fill_between(ref_freqs, mean_coh - sem_coh, mean_coh + sem_coh,
                            color=color, alpha=0.18)

        # Draw band boundaries as vertical lines
        for band in bands:
            ax.axvspan(band['fmin'], band['fmax'], alpha=0.04, color='gray')
            mid = (band['fmin'] + band['fmax']) / 2
            ax.text(mid, ymax * 0.97, band['name'], ha='center', va='top',
                    fontsize=7, color='#555555', rotation=90)

        r0 = next(iter(results.values()))
        ax.set_xlabel('Frequency (Hz)', fontsize=11)
        ax.set_ylabel('Coherence', fontsize=11)
        ax.set_xlim(fmin, fmax)
        ax.set_ylim(ymin, ymax)
        ax.set_title(
            f"Group Spectral Coherence  |  {r0['ch1']} ↔ {r0['ch2']}  "
            f"|  Method: {r0['method']}",
            fontsize=11, fontweight='bold')
        ax.legend(fontsize=9)
        ax.grid(True, alpha=0.3)
        fig.tight_layout()

        win = tk.Toplevel(self.root)
        win.title("Group Coherence Spectra Comparison")
        win.geometry("1050x560")
        cw = FigureCanvasTkAgg(fig, master=win)
        cw.draw()
        cw.get_tk_widget().pack(fill='both', expand=True)
        NavigationToolbar2Tk(cw, win).update()

    def visualize_group_coherence_bands(self):
        """Bar chart comparing group mean coherence per frequency band, with optional stats."""
        if not self.group_coherence_results:
            messagebox.showwarning("No Data",
                "Run '▶ Run Group Comparison' first.")
            return

        results = self.group_coherence_results
        bands = self._get_active_freq_bands()
        stats_test = self.grp_comp_stats_var.get()
        ymin = float(self.conn_params.get('coh_ymin', 0))
        ymax = float(self.conn_params.get('coh_ymax', 1))

        if not bands:
            messagebox.showwarning("No Bands",
                "No frequency bands are defined. Add bands in the Frequency Bands section.")
            return

        group_names = list(results.keys())
        n_groups = len(group_names)
        n_bands = len(bands)

        # Collect per-subject band means for each group
        group_band_data = {}   # gname -> list of arrays (n_subjects x n_bands)
        for gname, gdata in results.items():
            mat = []
            for sdata in gdata['subjects'].values():
                row = [self._band_mean_from_spectrum(sdata['freqs'], sdata['coh'], b)
                       for b in bands]
                mat.append(row)
            group_band_data[gname] = np.array(mat) if mat else np.empty((0, n_bands))

        # Figure
        fig, ax = plt.subplots(figsize=(max(8, n_bands * 1.4 + 1.5), 5.5))

        x = np.arange(n_bands)
        bar_width = min(0.7 / n_groups, 0.22)
        offsets = np.linspace(-(n_groups - 1) / 2, (n_groups - 1) / 2, n_groups) * bar_width

        for gi, gname in enumerate(group_names):
            color = self._GRP_PALETTE[gi % len(self._GRP_PALETTE)]
            mat = group_band_data[gname]
            if mat.shape[0] == 0:
                continue
            means = np.nanmean(mat, axis=0)
            sems  = (np.nanstd(mat, axis=0, ddof=1) / np.sqrt(mat.shape[0])
                     if mat.shape[0] > 1 else np.zeros(n_bands))
            n_subj = mat.shape[0]

            ax.bar(x + offsets[gi], means, bar_width,
                   color=color, alpha=0.82,
                   yerr=sems, capsize=4,
                   label=f"{gname} (n={n_subj})",
                   error_kw={'elinewidth': 1.4})

            # Scatter individual subject points
            for row in mat:
                jitter = np.random.uniform(-bar_width * 0.25, bar_width * 0.25, n_bands)
                ax.scatter(x + offsets[gi] + jitter, row,
                           color=color, s=18, alpha=0.55, zorder=5)

        # Statistical annotations between pairs (only for exactly 2 groups)
        if stats_test != 'None' and n_groups == 2:
            from scipy import stats as sp_stats
            g1_mat = group_band_data[group_names[0]]
            g2_mat = group_band_data[group_names[1]]
            for bi in range(n_bands):
                a = g1_mat[:, bi][~np.isnan(g1_mat[:, bi])]
                b = g2_mat[:, bi][~np.isnan(g2_mat[:, bi])]
                if len(a) < 2 or len(b) < 2:
                    continue
                if stats_test == 't-test':
                    _, pval = sp_stats.ttest_ind(a, b, equal_var=False)
                else:  # Mann-Whitney U
                    _, pval = sp_stats.mannwhitneyu(a, b, alternative='two-sided')

                sig = ('***' if pval < 0.001 else
                       '**'  if pval < 0.01  else
                       '*'   if pval < 0.05  else 'ns')
                top = max(
                    np.nanmean(g1_mat[:, bi]) + np.nanstd(g1_mat[:, bi], ddof=1) / np.sqrt(max(len(a),1)),
                    np.nanmean(g2_mat[:, bi]) + np.nanstd(g2_mat[:, bi], ddof=1) / np.sqrt(max(len(b),1)),
                )
                ax.text(x[bi], top + (ymax - ymin) * 0.03, sig,
                        ha='center', va='bottom', fontsize=10,
                        color='black' if sig != 'ns' else '#888888')

        ax.set_xticks(x)
        ax.set_xticklabels([b['name'] for b in bands], rotation=20, ha='right', fontsize=10)
        ax.set_ylabel('Mean Coherence', fontsize=11)
        ax.set_ylim(ymin, ymax)
        ax.legend(fontsize=9)
        ax.grid(True, axis='y', alpha=0.3)

        r0 = next(iter(results.values()))
        stat_label = f" | Stats: {stats_test}" if stats_test != 'None' else ''
        fig.suptitle(
            f"Group Coherence by Frequency Band  |  {r0['ch1']} ↔ {r0['ch2']}  "
            f"|  Method: {r0['method']}{stat_label}",
            fontsize=11, fontweight='bold')
        fig.tight_layout(rect=[0, 0, 1, 0.95])

        win = tk.Toplevel(self.root)
        win.title("Group Coherence Band Comparison")
        win.geometry(f"{min(1200, n_bands * 140 + 300)}x580")
        cw = FigureCanvasTkAgg(fig, master=win)
        cw.draw()
        cw.get_tk_widget().pack(fill='both', expand=True)
        NavigationToolbar2Tk(cw, win).update()

    def export_group_coherence_comparison(self):
        """Export per-subject per-band coherence data for all groups to CSV."""
        if not self.group_coherence_results:
            messagebox.showwarning("No Data",
                "Run '▶ Run Group Comparison' first.")
            return

        filepath = filedialog.asksaveasfilename(
            defaultextension='.csv',
            filetypes=[('CSV files', '*.csv'), ('All files', '*.*')],
            title="Save Group Coherence Comparison")
        if not filepath:
            return

        bands = self._get_active_freq_bands()
        rows = []

        for gname, gdata in self.group_coherence_results.items():
            ch1 = gdata['ch1']
            ch2 = gdata['ch2']
            for subj, sdata in gdata['subjects'].items():
                freqs = sdata['freqs']
                coh   = sdata['coh']
                # Per-band summary row
                base_row = {
                    'Group':   gname,
                    'Subject': subj,
                    'Ch1':     ch1,
                    'Ch2':     ch2,
                    'Method':  gdata.get('method', 'Welch'),
                    'Mean_Coherence_All': round(float(np.nanmean(coh)), 6),
                }
                for b in bands:
                    base_row[f"Band_{b['name']}_fmin"] = b['fmin']
                    base_row[f"Band_{b['name']}_fmax"] = b['fmax']
                    base_row[f"Band_{b['name']}_mean_coh"] = round(
                        self._band_mean_from_spectrum(freqs, coh, b), 6)
                rows.append(base_row)

        # Also write a per-frequency sheet
        freq_rows = []
        for gname, gdata in self.group_coherence_results.items():
            for subj, sdata in gdata['subjects'].items():
                for freq, coh_val in zip(sdata['freqs'], sdata['coh']):
                    freq_rows.append({
                        'Group': gname, 'Subject': subj,
                        'Ch1': gdata['ch1'], 'Ch2': gdata['ch2'],
                        'Frequency_Hz': round(float(freq), 6),
                        'Coherence':    round(float(coh_val), 6),
                    })

        # Save: band summary CSV + freq CSV side by side
        band_path = filepath
        freq_path = filepath.replace('.csv', '_per_frequency.csv')

        pd.DataFrame(rows).to_csv(band_path, index=False)
        pd.DataFrame(freq_rows).to_csv(freq_path, index=False)

        self.log_message(f"Group coherence exported: {band_path}")
        messagebox.showinfo("Export Complete",
            f"Band summary:      {band_path}\nPer-frequency: {freq_path}")

    # ------------------------------------------------------------------ #
    #  Bout-Epoch Group Comparison helpers                                 #
    # ------------------------------------------------------------------ #

    def _refresh_epoch_behavior_list_beg(self):
        """Populate the behavior combo for the bout-epoch group comparison panel."""
        behaviors = set()
        if self.processed_data:
            for data in self.processed_data.values():
                bouts = data.get('bouts', {})
                behaviors.update(str(b) for b in bouts if b not in ('onset_frames',))
        if not behaviors:
            boutframes_file = self.boutframes_path_var.get()
            if boutframes_file and os.path.exists(boutframes_file):
                try:
                    xl = pd.ExcelFile(boutframes_file)
                    for sheet in xl.sheet_names:
                        df = xl.parse(sheet, nrows=0)
                        behaviors.update(str(c) for c in df.columns)
                except Exception:
                    pass
        behaviors = sorted(behaviors)
        self.beg_behavior_combo['values'] = behaviors
        if behaviors and not self.beg_behavior_var.get():
            self.beg_behavior_var.set(behaviors[0])
        self.log_message(f"BEG behavior list refreshed: {', '.join(behaviors) or 'none found'}")

    def _refresh_beg_groups_listbox(self):
        """Populate the groups listbox for the bout-epoch group comparison panel."""
        if not hasattr(self, 'beg_groups_listbox'):
            return
        self.beg_groups_listbox.delete(0, 'end')
        for g in sorted(self.groups.keys()):
            n = len(self.groups[g])
            self.beg_groups_listbox.insert('end', f"{g}  (n={n})")

    def run_bout_epoch_group_comparison(self):
        """
        Compute per-subject bout-epoch coherence (pre/post onset) for every subject
        in the selected groups, then store results keyed by group for visualization.
        Reuses the same bout-epoch windows defined in the Bout Epoch Coherence section.
        """
        behavior = self.beg_behavior_var.get().strip()
        if not behavior:
            messagebox.showwarning("No Behavior",
                "Enter or select a behavior and click ↺ Refresh.")
            return

        sel = self.beg_groups_listbox.curselection()
        if not sel:
            messagebox.showwarning("No Groups",
                "Select at least two groups from the list.")
            return

        raw_names = [self.beg_groups_listbox.get(i) for i in sel]
        selected_groups = [n.rsplit('  (n=', 1)[0].strip() for n in raw_names]

        if len(selected_groups) < 2:
            messagebox.showwarning("Too Few Groups",
                "Select at least two groups to compare.")
            return

        try:
            pre_sec   = float(self.bout_epoch_pre_var.get())
            post_sec  = float(self.bout_epoch_post_var.get())
            max_bouts = int(float(self.bout_epoch_max_bouts_var.get()))
        except ValueError:
            messagebox.showerror("Invalid Input",
                "Seconds before/after onset and max bouts must be numbers.")
            return
        if pre_sec <= 0 or post_sec <= 0 or max_bouts < 0:
            messagebox.showerror("Invalid Input",
                "Pre/post seconds must be > 0 and max bouts must be ≥ 0.")
            return

        ch1 = self.conn_channel1_var.get()
        ch2 = self.conn_channel2_var.get()
        if ch1 == ch2:
            messagebox.showwarning("Invalid Channels",
                "Please select two different channels.")
            return

        boutframes_file = self.boutframes_path_var.get()
        _use_file_fallback = bool(boutframes_file and os.path.exists(boutframes_file))
        use_excl = self.use_exclusions_conn.get()
        fs = float(self.params.get('fps', 30))
        pre_samples  = int(pre_sec * fs)
        post_samples = int(post_sec * fs)
        coh_nperseg_sec = min(
            self.conn_params.get('static_nperseg_sec', 10.0),
            min(pre_sec, post_sec) / 3.0)
        coh_method   = self.conn_params.get('coherence_method', 'Welch')
        morlet_n     = int(self.conn_params.get('morlet_n_freqs', 50))
        morlet_w     = float(self.conn_params.get('morlet_w', 6.0))
        fmin         = self.conn_params['static_fmin']
        fmax         = self.conn_params['static_fmax']
        bands        = self._get_active_freq_bands()

        total_subjects = sum(
            len(self.groups.get(g, [])) for g in selected_groups)

        # Storage: { group_name: { subject: {pre_freqs, pre_coh_mean, post_coh_mean,
        #                                     pre_coh_sem, post_coh_sem, n_bouts, ...} } }
        self.beg_results = {}
        _pd     = self.processed_data
        _groups = self.groups
        _cp     = dict(self.conn_params)

        def _worker(q):
            done = 0
            for gname in selected_groups:
                members = _groups.get(gname, [])
                group_entry = {}

                for subj in members:
                    done += 1
                    q.put(('status',
                           f"Group '{gname}' — {subj}  ({done}/{total_subjects})"))

                    if subj not in _pd:
                        continue
                    if use_excl and (self.is_subject_channel_excluded(subj, ch1) or
                                     self.is_subject_channel_excluded(subj, ch2)):
                        q.put(('log', f"  Skipping {subj}: channel excluded"))
                        continue

                    data = _pd[subj]
                    stored_bouts = data.get('bouts', {})

                    # Resolve behavior key (case-insensitive)
                    beh_key = behavior if behavior in stored_bouts else next(
                        (k for k in stored_bouts
                         if str(k).lower() == behavior.lower()), None)

                    onset_frames = []
                    if beh_key and 'onset_frames' in stored_bouts.get(beh_key, {}):
                        onset_frames = stored_bouts[beh_key]['onset_frames']
                    elif _use_file_fallback:
                        try:
                            df_b = pd.read_excel(boutframes_file, sheet_name=subj)
                            cols_ci = {str(c).lower(): c for c in df_b.columns}
                            bcol = cols_ci.get(behavior.lower())
                            if bcol:
                                onset_frames = (pd.to_numeric(df_b[bcol], errors='coerce')
                                                .dropna().astype(int).tolist())
                        except Exception as exc:
                            q.put(('log', f"  Skipping {subj}: {exc}"))

                    if not onset_frames:
                        q.put(('log', f"  Skipping {subj}: no onset frames for '{behavior}'"))
                        continue

                    n_avail = len(onset_frames)
                    if max_bouts > 0 and n_avail > max_bouts:
                        onset_frames = onset_frames[:max_bouts]

                    s1 = self._get_channel_signal(data, ch1)
                    s2 = self._get_channel_signal(data, ch2)
                    if s1 is None or s2 is None:
                        q.put(('log', f"  Skipping {subj}: channel data missing"))
                        continue

                    n_sig = len(s1)
                    pre_list, post_list = [], []
                    pre_freqs = post_freqs = None
                    n_used = 0

                    for onset in onset_frames:
                        p_start = onset - pre_samples
                        p_end   = onset + post_samples
                        if p_start < 0 or p_end > n_sig:
                            continue
                        pre_s1  = s1[p_start:onset]
                        pre_s2  = s2[p_start:onset]
                        post_s1 = s1[onset:p_end]
                        post_s2 = s2[onset:p_end]

                        if coh_method == 'Morlet Wavelet':
                            pre_r  = self.calculate_static_coherence_morlet(
                                pre_s1, pre_s2, fs=fs, fmin=fmin, fmax=fmax,
                                n_freqs=morlet_n, w=morlet_w)
                            post_r = self.calculate_static_coherence_morlet(
                                post_s1, post_s2, fs=fs, fmin=fmin, fmax=fmax,
                                n_freqs=morlet_n, w=morlet_w)
                        else:
                            pre_r  = self.calculate_static_coherence(
                                pre_s1, pre_s2, fs=fs, fmin=fmin, fmax=fmax,
                                nperseg=coh_nperseg_sec)
                            post_r = self.calculate_static_coherence(
                                post_s1, post_s2, fs=fs, fmin=fmin, fmax=fmax,
                                nperseg=coh_nperseg_sec)

                        if pre_r is None or post_r is None:
                            continue
                        pre_list.append(pre_r['coh'])
                        post_list.append(post_r['coh'])
                        if pre_freqs is None:
                            pre_freqs  = pre_r['freqs']
                            post_freqs = post_r['freqs']
                        n_used += 1

                    if n_used == 0:
                        q.put(('log', f"  {subj}: no valid epochs"))
                        continue

                    pre_arr  = np.vstack(pre_list)
                    post_arr = np.vstack(post_list)
                    n_b = n_used
                    pre_m  = np.mean(pre_arr,  axis=0)
                    post_m = np.mean(post_arr, axis=0)
                    pre_s  = np.std(pre_arr,  axis=0) / np.sqrt(n_b) if n_b > 1 else np.zeros_like(pre_m)
                    post_s = np.std(post_arr, axis=0) / np.sqrt(n_b) if n_b > 1 else np.zeros_like(post_m)

                    # Band means for pre & post
                    pre_bands  = {b['name']: self._band_mean_from_spectrum(pre_freqs,  pre_m,  b) for b in bands}
                    post_bands = {b['name']: self._band_mean_from_spectrum(post_freqs, post_m, b) for b in bands}
                    delta_bands = {b['name']: post_bands[b['name']] - pre_bands[b['name']] for b in bands}

                    group_entry[subj] = {
                        'pre_freqs':     pre_freqs,
                        'post_freqs':    post_freqs,
                        'pre_coh_mean':  pre_m,
                        'post_coh_mean': post_m,
                        'pre_coh_sem':   pre_s,
                        'post_coh_sem':  post_s,
                        'pre_bands':     pre_bands,
                        'post_bands':    post_bands,
                        'delta_bands':   delta_bands,
                        'n_bouts':       n_used,
                        'n_bouts_available': n_avail,
                    }
                    q.put(('log',
                           f"  {subj}: {n_used}/{n_avail} bouts — "
                           f"mean pre={np.mean(pre_m):.4f}, post={np.mean(post_m):.4f}"))

                if group_entry:
                    self.beg_results[gname] = {
                        'subjects': group_entry,
                        'behavior': behavior,
                        'ch1': ch1, 'ch2': ch2,
                        'pre_sec': pre_sec, 'post_sec': post_sec,
                        'method': coh_method,
                    }
                    q.put(('log',
                           f"Group '{gname}': {len(group_entry)}/{len(members)} subjects processed."))

        def _on_done():
            n_grp = len(self.beg_results)
            msg = (f"{n_grp} group(s) processed — behavior: '{behavior}'.  "
                   f"Click a plot button to visualize.")
            self.beg_status_var.set(msg)
            self.log_message(f"Bout-epoch group comparison complete — {n_grp} group(s).")
            if not self.beg_results:
                messagebox.showwarning("No Results",
                    "No subjects could be processed. Check that groups are defined "
                    "and that the behavior exists in boutframes / processed data.")

        self._run_with_progress(
            f"Bout-Epoch Group Comparison  ('{behavior}')", _worker, _on_done)

    # ── Shared grand-mean helper ───────────────────────────────────────────
    def _beg_group_grand_mean(self, group_entry, epoch='pre'):
        """Return (freqs, mean, sem, n) grand-mean spectrum across all subjects in a group entry."""
        subjects = group_entry['subjects']
        key_m = f'{epoch}_coh_mean'
        key_f = f'{epoch}_freqs'
        ref_freqs = next(iter(subjects.values()))[key_f]
        stack = []
        for sdata in subjects.values():
            f = sdata[key_f]
            c = sdata[key_m]
            if len(f) == len(ref_freqs) and np.allclose(f, ref_freqs):
                stack.append(c)
            else:
                stack.append(np.interp(ref_freqs, f, c))
        arr = np.vstack(stack)
        n = arr.shape[0]
        return (ref_freqs,
                np.mean(arr, axis=0),
                np.std(arr, axis=0, ddof=1) / np.sqrt(n) if n > 1 else np.zeros(arr.shape[1]),
                n)

    def visualize_beg_spectra(self):
        """
        Plot grand-mean coherence spectra (pre vs post) for each group side by side.
        Each group gets its own subplot; pre=solid, post=dashed.
        """
        if not hasattr(self, 'beg_results') or not self.beg_results:
            messagebox.showwarning("No Data",
                "Run '▶ Run Bout-Epoch Group Comparison' first.")
            return

        results = self.beg_results
        show_traces = self.beg_show_traces_var.get()
        ymin = float(self.conn_params.get('coh_ymin', 0))
        ymax = float(self.conn_params.get('coh_ymax', 1))
        fxmin = float(self.conn_params.get('freq_xmin', 0))
        fxmax = float(self.conn_params.get('freq_xmax', 10))
        bands = self._get_active_freq_bands()

        group_names = list(results.keys())
        n_grp = len(group_names)

        # Layout: top row = spectra per group; bottom row = grand-mean overlay
        ncols = max(n_grp, 1)
        fig, axes = plt.subplots(2, ncols,
                                 figsize=(max(5 * ncols, 8), 9),
                                 squeeze=False)

        r0 = next(iter(results.values()))

        for gi, gname in enumerate(group_names):
            color = self._GRP_PALETTE[gi % len(self._GRP_PALETTE)]
            gdata = results[gname]
            ax = axes[0][gi]

            freqs_post, mean_post, sem_post, n_post = self._beg_group_grand_mean(gdata, 'post')

            if show_traces:
                for sdata in gdata['subjects'].values():
                    ax.plot(sdata['post_freqs'], sdata['post_coh_mean'],
                            color=color, lw=0.5, alpha=0.3)

            ax.plot(freqs_post, mean_post, color=color, lw=2.0,
                    label=f"Post-onset (+{r0['post_sec']:.0f}s)")
            ax.fill_between(freqs_post, mean_post - sem_post, mean_post + sem_post,
                            color=color, alpha=0.18)

            # Band shading
            for band in bands:
                ax.axvspan(band['fmin'], band['fmax'], alpha=0.05, color='gray')

            ax.set_xlim(fxmin, fxmax)
            ax.set_ylim(ymin, ymax)
            ax.set_xlabel('Frequency (Hz)', fontsize=9)
            ax.set_ylabel('Coherence', fontsize=9)
            ax.set_title(f"{gname}\n(n={n_post} subjects, {sum(s['n_bouts'] for s in gdata['subjects'].values())} bouts)",
                         fontsize=9, fontweight='bold')
            ax.legend(fontsize=7)
            ax.grid(True, alpha=0.3)

        # Bottom row: overlay all groups — pre (solid) and post (dashed)
        ax_ov = fig.add_subplot(2, 1, 2)  # spans full width
        for spine in [axes[1][gi].get_position() for gi in range(ncols)]:
            pass
        # Remove bottom subplot placeholders
        for gi in range(ncols):
            fig.delaxes(axes[1][gi])
        ax_ov = fig.add_axes([0.07, 0.05, 0.90, 0.35])

        for gi, gname in enumerate(group_names):
            color = self._GRP_PALETTE[gi % len(self._GRP_PALETTE)]
            gdata = results[gname]
            freqs_post, mean_post, sem_post, _ = self._beg_group_grand_mean(gdata, 'post')
            n_subj = len(gdata['subjects'])
            n_bouts = sum(s['n_bouts'] for s in gdata['subjects'].values())

            ax_ov.plot(freqs_post, mean_post, color=color, lw=2.2,
                       label=f"{gname} (n={n_subj}, {n_bouts} bouts)")
            ax_ov.fill_between(freqs_post, mean_post - sem_post, mean_post + sem_post,
                               color=color, alpha=0.15)

        ax_ov.set_xlim(fxmin, fxmax)
        ax_ov.set_ylim(ymin, ymax)
        ax_ov.set_xlabel('Frequency (Hz)', fontsize=10)
        ax_ov.set_ylabel('Coherence', fontsize=10)
        ax_ov.set_title('All Groups Overlay — Post-onset Grand Mean ± SEM',
                        fontsize=10, fontweight='bold')
        ax_ov.legend(fontsize=7, ncol=min(n_grp, 6))
        ax_ov.grid(True, alpha=0.3)

        fig.suptitle(
            f"Bout-Epoch Coherence by Group  |  {r0['ch1']} ↔ {r0['ch2']}  "
            f"|  Behavior: {r0['behavior']}  |  Method: {r0['method']}",
            fontsize=11, fontweight='bold', y=0.99)

        win = tk.Toplevel(self.root)
        win.title("Bout-Epoch Group Coherence Spectra")
        win.geometry("1200x820")
        cw = FigureCanvasTkAgg(fig, master=win)
        cw.draw()
        cw.get_tk_widget().pack(fill='both', expand=True)
        NavigationToolbar2Tk(cw, win).update()

    def visualize_beg_band_bars(self):
        """
        Bar chart: post-onset coherence per frequency band.
        Layout: ONE subplot per spectral band, all groups shown side-by-side
        on each subplot with individual subject dots overlaid.
        """
        if not hasattr(self, 'beg_results') or not self.beg_results:
            messagebox.showwarning("No Data",
                "Run '▶ Run Bout-Epoch Group Comparison' first.")
            return

        results    = self.beg_results
        all_bands  = self._get_active_freq_bands()
        stats_test = self.beg_stats_var.get()
        ymin = float(self.conn_params.get('coh_ymin', 0))
        ymax = float(self.conn_params.get('coh_ymax', 1))

        if not all_bands:
            messagebox.showwarning("No Bands",
                "Add frequency bands in the Frequency Bands section.")
            return

        group_names = list(results.keys())
        n_grp = len(group_names)
        r_any = next(iter(results.values()))

        # Collect per-subject post-onset band means for every group
        # gbd[gname] = ndarray (n_subjects × n_all_bands)
        gbd = {}
        for gname, gdata in results.items():
            rows = []
            for sdata in gdata['subjects'].values():
                rows.append([
                    self._band_mean_from_spectrum(
                        sdata['post_freqs'], sdata['post_coh_mean'], b)
                    for b in all_bands
                ])
            gbd[gname] = np.array(rows) if rows else np.empty((0, len(all_bands)))

        # Keep only bands that have at least one non-NaN value across all groups
        active_idx = [
            bi for bi, b in enumerate(all_bands)
            if any(
                not np.all(np.isnan(gbd[g][:, bi]))
                for g in group_names if gbd[g].shape[0] > 0
            )
        ]
        if not active_idx:
            messagebox.showwarning("No Data",
                "No frequency band data found in the current results.")
            return
        bands = [all_bands[i] for i in active_idx]
        n_band = len(bands)

        # Slice gbd to active bands only
        for gname in group_names:
            if gbd[gname].shape[0] > 0:
                gbd[gname] = gbd[gname][:, active_idx]
            else:
                gbd[gname] = np.empty((0, n_band))

        # Layout: one subplot per band
        ncols = min(n_band, 4)
        nrows = int(np.ceil(n_band / ncols))
        fig, axes = plt.subplots(nrows, ncols,
                                 figsize=(max(4.5 * ncols, 7), 4.5 * nrows),
                                 squeeze=False)

        x_grp = np.arange(n_grp)
        bar_w = min(0.65, 0.65)

        for bi, band in enumerate(bands):
            ax = axes[bi // ncols][bi % ncols]

            means, sems, colors, ns = [], [], [], []
            for gi, gname in enumerate(group_names):
                mat = gbd[gname]
                col = mat[:, bi] if mat.shape[0] > 0 else np.array([])
                col = col[~np.isnan(col)]
                n_s = len(col)
                ns.append(n_s)
                means.append(float(np.nanmean(col)) if n_s > 0 else 0.0)
                sems.append(float(np.nanstd(col, ddof=1) / np.sqrt(n_s))
                            if n_s > 1 else 0.0)
                colors.append(self._GRP_PALETTE[gi % len(self._GRP_PALETTE)])

            ax.bar(x_grp, means, bar_w,
                   color=colors, alpha=0.82,
                   yerr=sems, capsize=4,
                   error_kw={'elinewidth': 1.4})

            # Individual subject dots per group
            for gi, gname in enumerate(group_names):
                mat = gbd[gname]
                if mat.shape[0] == 0:
                    continue
                vals = mat[:, bi]
                jit = np.random.uniform(-0.12, 0.12, len(vals))
                ax.scatter(x_grp[gi] + jit, vals,
                           color=colors[gi], s=22, alpha=0.60, zorder=5,
                           edgecolors='white', linewidths=0.4)

            # Stats annotations between groups (independent t-test / Mann-Whitney)
            if stats_test != 'None' and n_grp >= 2:
                from scipy import stats as sp_stats
                # Compare each pair of groups; annotate pairs with significance
                y_top = max(m + s for m, s in zip(means, sems)) + (ymax - ymin) * 0.04
                step  = (ymax - ymin) * 0.08
                pair_idx = 0
                for ga in range(n_grp):
                    for gb in range(ga + 1, n_grp):
                        a = gbd[group_names[ga]][:, bi]
                        b_vals = gbd[group_names[gb]][:, bi]
                        a = a[~np.isnan(a)]
                        b_vals = b_vals[~np.isnan(b_vals)]
                        if len(a) < 2 or len(b_vals) < 2:
                            pair_idx += 1
                            continue
                        if stats_test == 't-test':
                            _, pval = sp_stats.ttest_ind(a, b_vals, equal_var=False)
                        else:
                            _, pval = sp_stats.mannwhitneyu(a, b_vals, alternative='two-sided')
                        sig = ('***' if pval < 0.001 else
                               '**'  if pval < 0.01  else
                               '*'   if pval < 0.05  else 'ns')
                        y_ann = y_top + pair_idx * step
                        x_mid = (x_grp[ga] + x_grp[gb]) / 2.0
                        ax.plot([x_grp[ga], x_grp[gb]], [y_ann, y_ann],
                                color='black', lw=0.8)
                        ax.text(x_mid, y_ann + (ymax - ymin) * 0.01, sig,
                                ha='center', va='bottom', fontsize=8,
                                color='black' if sig != 'ns' else '#999999')
                        pair_idx += 1

            group_labels = [f"{g}\n(n={ns[gi]})" for gi, g in enumerate(group_names)]
            ax.set_xticks(x_grp)
            ax.set_xticklabels(group_labels, fontsize=8)
            ax.set_ylabel('Mean Coherence', fontsize=9)
            ax.set_ylim(ymin, ymax)
            ax.set_title(f"{band['name']}  ({band['fmin']}–{band['fmax']} Hz)",
                         fontsize=9, fontweight='bold')
            ax.grid(True, axis='y', alpha=0.3)

        # Hide unused subplots
        for bi in range(n_band, nrows * ncols):
            fig.delaxes(axes[bi // ncols][bi % ncols])

        stat_label = f" | Stats: {stats_test}" if stats_test != 'None' else ''
        post_sec = r_any.get('post_sec', '?')
        fig.suptitle(
            f"Post-onset Coherence by Band  |  {r_any['ch1']} ↔ {r_any['ch2']}  "
            f"|  Behavior: {r_any['behavior']}  |  +{post_sec:.0f}s{stat_label}",
            fontsize=11, fontweight='bold')
        fig.tight_layout(rect=[0, 0, 1, 0.95])

        win = tk.Toplevel(self.root)
        win.title("Bout-Epoch Group Band Bars")
        win.geometry(f"{min(1400, max(700, n_band * 320))}x{min(900, 500 * nrows)}")
        cw = FigureCanvasTkAgg(fig, master=win)
        cw.draw()
        cw.get_tk_widget().pack(fill='both', expand=True)
        NavigationToolbar2Tk(cw, win).update()

    def visualize_beg_delta(self):
        """
        Plot the change in coherence (post − pre) per frequency band per group,
        grouped bar chart with group-level statistical comparisons.
        """
        if not hasattr(self, 'beg_results') or not self.beg_results:
            messagebox.showwarning("No Data",
                "Run '▶ Run Bout-Epoch Group Comparison' first.")
            return

        results   = self.beg_results
        bands     = self._get_active_freq_bands()
        stats_test = self.beg_stats_var.get()

        if not bands:
            messagebox.showwarning("No Bands",
                "Add frequency bands in the Frequency Bands section.")
            return

        group_names = list(results.keys())
        n_grp  = len(group_names)
        n_band = len(bands)

        # Per-subject delta (post − pre) per band
        gbd = {}
        for gname, gdata in results.items():
            delta_rows = []
            for sdata in gdata['subjects'].values():
                pre_vals  = [self._band_mean_from_spectrum(sdata['pre_freqs'],  sdata['pre_coh_mean'],  b) for b in bands]
                post_vals = [self._band_mean_from_spectrum(sdata['post_freqs'], sdata['post_coh_mean'], b) for b in bands]
                delta_rows.append([po - pr for pr, po in zip(pre_vals, post_vals)])
            gbd[gname] = np.array(delta_rows) if delta_rows else np.empty((0, n_band))

        # Filter out bands where every group has only NaN (frequency range outside data)
        active_idx = [
            bi for bi in range(n_band)
            if any(
                not np.all(np.isnan(gbd[g][:, bi]))
                for g in group_names if gbd[g].shape[0] > 0
            )
        ]
        if not active_idx:
            messagebox.showwarning("No Data",
                "No frequency band data found — the current frequency range may not overlap the defined bands.")
            return
        bands   = [bands[i] for i in active_idx]
        n_band  = len(bands)
        for gname in group_names:
            if gbd[gname].shape[0] > 0:
                gbd[gname] = gbd[gname][:, active_idx]
            else:
                gbd[gname] = np.empty((0, n_band))

        fig, ax = plt.subplots(figsize=(max(8, n_band * 1.4 + 2), 5.5))
        x = np.arange(n_band)
        bar_w = min(0.7 / n_grp, 0.22)
        offsets = np.linspace(-(n_grp - 1) / 2, (n_grp - 1) / 2, n_grp) * bar_w

        for gi, gname in enumerate(group_names):
            color = self._GRP_PALETTE[gi % len(self._GRP_PALETTE)]
            mat   = gbd[gname]
            if mat.shape[0] == 0:
                continue
            n_s   = mat.shape[0]
            means = np.nanmean(mat, axis=0)
            sems  = (np.nanstd(mat, axis=0, ddof=1) / np.sqrt(n_s)
                     if n_s > 1 else np.zeros(n_band))

            ax.bar(x + offsets[gi], means, bar_w,
                   color=color, alpha=0.82,
                   yerr=sems, capsize=4,
                   label=f"{gname} (n={n_s})",
                   error_kw={'elinewidth': 1.4})

            # Individual subject dots
            for row in mat:
                jit = np.random.uniform(-bar_w * 0.25, bar_w * 0.25, n_band)
                ax.scatter(x + offsets[gi] + jit, row,
                           color=color, s=18, alpha=0.55, zorder=5)

        # Horizontal zero line
        ax.axhline(0, color='black', lw=0.8, linestyle='--', alpha=0.6)

        # Stats between groups (only for exactly 2 groups)
        if stats_test != 'None' and n_grp == 2:
            from scipy import stats as sp_stats
            g1 = gbd[group_names[0]]
            g2 = gbd[group_names[1]]
            y_range = ax.get_ylim()
            for bi in range(n_band):
                a = g1[:, bi][~np.isnan(g1[:, bi])]
                b_v = g2[:, bi][~np.isnan(g2[:, bi])]
                if len(a) < 2 or len(b_v) < 2:
                    continue
                if stats_test == 't-test':
                    _, pval = sp_stats.ttest_ind(a, b_v, equal_var=False)
                else:
                    _, pval = sp_stats.mannwhitneyu(a, b_v, alternative='two-sided')
                sig = ('***' if pval < 0.001 else
                       '**'  if pval < 0.01  else
                       '*'   if pval < 0.05  else 'ns')
                top = max(
                    np.nanmean(g1[:, bi]) + np.nanstd(g1[:, bi], ddof=1) / np.sqrt(max(len(a), 1)),
                    np.nanmean(g2[:, bi]) + np.nanstd(g2[:, bi], ddof=1) / np.sqrt(max(len(b_v), 1)),
                )
                y_span = abs(ax.get_ylim()[1] - ax.get_ylim()[0])
                ax.text(x[bi], top + y_span * 0.04, sig,
                        ha='center', va='bottom', fontsize=10,
                        color='black' if sig != 'ns' else '#888888')

        ax.set_xticks(x)
        ax.set_xticklabels([b['name'] for b in bands], rotation=20, ha='right', fontsize=10)
        ax.set_ylabel('Δ Coherence (post − baseline)', fontsize=11)
        ax.legend(fontsize=9)
        ax.grid(True, axis='y', alpha=0.3)

        r_any = next(iter(results.values()))
        stat_label = f" | Stats: {stats_test}" if stats_test != 'None' else ''
        fig.suptitle(
            f"Δ Coherence (Post − Baseline) by Band & Group  "
            f"|  {r_any['ch1']} ↔ {r_any['ch2']}  "
            f"|  Behavior: {r_any['behavior']}{stat_label}",
            fontsize=11, fontweight='bold')
        fig.tight_layout(rect=[0, 0, 1, 0.95])

        win = tk.Toplevel(self.root)
        win.title("Δ Coherence by Group")
        win.geometry(f"{min(1200, n_band * 140 + 300)}x560")
        cw = FigureCanvasTkAgg(fig, master=win)
        cw.draw()
        cw.get_tk_widget().pack(fill='both', expand=True)
        NavigationToolbar2Tk(cw, win).update()

    # ------------------------------------------------------------------ #
    #  BEG Peri-Event Spectrogram (group-level, with contrast option)     #
    # ------------------------------------------------------------------ #
    def visualize_beg_peri_event_spectrogram(self):
        """
        Peri-event time-frequency heatmap computed from the BEG comparison
        groups.  Shows one grand-mean spectrogram per group, plus an optional
        difference image (Group A − Group B) using a diverging colormap.

        Epoch extraction mirrors visualize_bout_epoch_spectrogram but
        averages per group rather than per subject.
        """
        if not hasattr(self, 'beg_results') or not self.beg_results:
            messagebox.showwarning("No Data",
                "Run '▶ Run Bout-Epoch Group Comparison' first.")
            return

        results     = self.beg_results
        group_names = list(results.keys())
        n_grp       = len(group_names)
        if n_grp == 0:
            return

        # ── Group selection dialog ────────────────────────────────────
        chosen_groups = {'names': []}
        if n_grp == 1:
            chosen_groups['names'] = group_names[:]
        else:
            grp_dlg = tk.Toplevel(self.root)
            grp_dlg.title("Select Groups to Plot")
            grp_dlg.geometry("340x300")
            grp_dlg.transient(self.root)
            grp_dlg.grab_set()

            ttk.Label(grp_dlg, text="Select groups to include in the spectrogram:",
                      font=('Segoe UI', 10)).pack(anchor='w', padx=12, pady=(12, 4))

            lb_frame = ttk.Frame(grp_dlg)
            lb_frame.pack(fill='both', expand=True, padx=12, pady=4)
            _sb = ttk.Scrollbar(lb_frame)
            _sb.pack(side='right', fill='y')
            _lb = tk.Listbox(lb_frame, selectmode='multiple',
                             yscrollcommand=_sb.set, height=8)
            _lb.pack(fill='both', expand=True)
            _sb.config(command=_lb.yview)
            for g in group_names:
                _lb.insert('end', g)
            for i in range(len(group_names)):
                _lb.selection_set(i)  # default: all selected

            def _ok_grp():
                chosen_groups['names'] = [_lb.get(i) for i in _lb.curselection()]
                grp_dlg.destroy()

            btn_r = ttk.Frame(grp_dlg)
            btn_r.pack(fill='x', padx=12, pady=10)
            ttk.Button(btn_r, text="Continue", command=_ok_grp).pack(side='left', padx=4)
            ttk.Button(btn_r, text="Cancel", command=grp_dlg.destroy).pack(side='left', padx=4)
            grp_dlg.wait_window()
            if not chosen_groups['names']:
                return

        selected_group_names = chosen_groups['names']
        r0_g  = results[selected_group_names[0]]
        r0_s  = next(iter(r0_g['subjects'].values()))
        behavior = r0_g.get('behavior', '')
        ch1      = r0_g.get('ch1', 'G0')
        ch2      = r0_g.get('ch2', 'G1')
        pre_sec  = r0_g.get('pre_sec', 10.0)
        post_sec = r0_g.get('post_sec', 10.0)
        method   = r0_g.get('method', 'Morlet Wavelet')

        fs          = self.params.get('fps', 30)
        pre_samples = int(pre_sec  * fs)
        post_samples= int(post_sec * fs)
        epoch_len   = pre_samples + post_samples

        fmin    = self.conn_params.get('static_fmin', 0.05)
        fmax    = self.conn_params.get('static_fmax', 3.0)
        n_freqs = int(self.conn_params.get('morlet_n_freqs', 50))
        w_par   = float(self.conn_params.get('morlet_w', 6.0))

        freqs      = np.logspace(np.log10(max(fmin, 1e-3)), np.log10(fmax), n_freqs)
        scales     = (w_par * fs) / (2.0 * np.pi * freqs)
        smooth_len = max(3, int(fs * 1.0))
        times      = np.linspace(-pre_sec, post_sec, epoch_len)

        import matplotlib.ticker as mticker
        from scipy.ndimage import uniform_filter1d

        _parula_colors = [
            [0.2081, 0.1663, 0.5292], [0.2116, 0.1870, 0.5770],
            [0.2123, 0.2137, 0.6271], [0.1959, 0.2444, 0.6730],
            [0.1559, 0.2780, 0.7202], [0.0859, 0.3141, 0.7676],
            [0.0396, 0.3425, 0.7965], [0.0273, 0.3697, 0.8118],
            [0.0433, 0.4011, 0.8186], [0.0725, 0.4328, 0.8145],
            [0.0956, 0.4642, 0.8011], [0.1043, 0.4943, 0.7832],
            [0.0991, 0.5238, 0.7640], [0.0802, 0.5527, 0.7436],
            [0.0560, 0.5809, 0.7218], [0.0369, 0.6079, 0.6979],
            [0.0420, 0.6334, 0.6706], [0.0713, 0.6573, 0.6401],
            [0.1195, 0.6792, 0.6063], [0.1729, 0.6994, 0.5696],
            [0.2309, 0.7178, 0.5300], [0.2895, 0.7346, 0.4879],
            [0.3490, 0.7499, 0.4436], [0.4089, 0.7638, 0.3975],
            [0.4694, 0.7765, 0.3501], [0.5298, 0.7880, 0.3018],
            [0.5900, 0.7984, 0.2533], [0.6498, 0.8077, 0.2051],
            [0.7091, 0.8160, 0.1578], [0.7675, 0.8233, 0.1119],
            [0.8248, 0.8296, 0.0681], [0.8809, 0.8349, 0.0274],
            [0.9355, 0.8392, 0.0000], [0.9880, 0.8423, 0.0000],
            [0.9987, 0.8637, 0.1165], [0.9919, 0.9000, 0.2729],
            [0.9826, 0.9341, 0.4242], [0.9769, 0.9657, 0.5714],
            [0.9839, 0.9874, 0.7013], [1.0000, 1.0000, 0.8510],
        ]
        parula = LinearSegmentedColormap.from_list('parula', _parula_colors, N=256)

        def _epoch_spectrogram_for_subjects(subject_list):
            """Compute grand-mean CWT coherence matrix across all subjects in the list."""
            accum   = np.zeros((n_freqs, epoch_len))
            n_total = 0
            for subject in subject_list:
                data = self.processed_data.get(subject)
                if data is None:
                    continue
                stored_bouts = data.get('bouts', {})
                _beh_key = behavior if behavior in stored_bouts else next(
                    (k for k in stored_bouts if str(k).lower() == behavior.lower()), None)

                onset_frames = []
                if _beh_key and 'onset_frames' in stored_bouts.get(_beh_key, {}):
                    onset_frames = stored_bouts[_beh_key]['onset_frames']
                else:
                    bfp = self.boutframes_path_var.get()
                    if bfp and os.path.exists(bfp):
                        try:
                            df_b = pd.read_excel(bfp, sheet_name=subject)
                            cols_ci = {str(c).lower(): c for c in df_b.columns}
                            bcol = cols_ci.get(behavior.lower())
                            if bcol:
                                raw_f = (pd.to_numeric(df_b[bcol], errors='coerce')
                                         .dropna().to_numpy(dtype=float))
                                _sc = 1.0
                                if self.params.get('auto_scale_boutframes', False):
                                    _vf = float(self.params.get('boutframes_video_fps', 30))
                                    _pf = data.get('photometry_fps',
                                                   getattr(self, 'detected_photometry_fps', None))
                                    if _pf and _vf > 0 and abs(_pf - _vf) > 0.1:
                                        _sc = _pf / _vf
                                if _sc != 1.0:
                                    raw_f = np.round(raw_f * _sc)
                                raw_f = raw_f.astype(int)
                                _ms = int(self.params.get('boutframe_manual_shift', 0))
                                if _ms:
                                    raw_f += _ms
                                _ps = self._get_per_subject_shift(subject)
                                if _ps:
                                    raw_f += _ps
                                if self.params.get('precut_correct_boutframes', True):
                                    _pc = int(self.params.get('precut', 0))
                                    _nl = int(data.get('n_led_states', 1))
                                    _off = _pc // max(1, _nl)
                                    if _off > 0:
                                        raw_f = raw_f - _off
                                _excl = int(self.params.get('exclude_frames_before', 0))
                                onset_frames = raw_f[raw_f >= _excl].tolist()
                        except Exception:
                            pass

                if not onset_frames:
                    continue

                sig1 = self._get_channel_signal(data, ch1)
                sig2 = self._get_channel_signal(data, ch2)
                if sig1 is None or sig2 is None:
                    continue

                n_sig = len(sig1)
                for onset in onset_frames:
                    start = onset - pre_samples
                    end   = onset + post_samples
                    if start < 0 or end > n_sig:
                        continue
                    seg1 = np.asarray(sig1[start:end], dtype=float)
                    seg2 = np.asarray(sig2[start:end], dtype=float)
                    if np.any(np.isnan(seg1)) or np.any(np.isnan(seg2)):
                        continue
                    W1 = self._morlet_cwt(seg1, scales, w=w_par)
                    W2 = self._morlet_cwt(seg2, scales, w=w_par)
                    S12 = W1 * np.conj(W2)
                    S11 = np.abs(W1) ** 2
                    S22 = np.abs(W2) ** 2
                    S12s = (uniform_filter1d(S12.real, smooth_len, axis=1)
                            + 1j * uniform_filter1d(S12.imag, smooth_len, axis=1))
                    S11s = uniform_filter1d(S11, smooth_len, axis=1)
                    S22s = uniform_filter1d(S22, smooth_len, axis=1)
                    coh  = np.clip(np.abs(S12s)**2 / (S11s * S22s + 1e-30), 0.0, 1.0)
                    accum   += coh
                    n_total += 1

            return (accum / n_total) if n_total > 0 else None, n_total

        # ── Run progress dialog while computing ───────────────────────
        group_matrices = {}
        group_bouts    = {}

        n_selected = len(selected_group_names)
        progress_win = tk.Toplevel(self.root)
        progress_win.title("Computing group spectrograms…")
        progress_win.geometry("340x100")
        progress_win.transient(self.root)
        progress_win.grab_set()
        prog_lbl = ttk.Label(progress_win, text="Starting…")
        prog_lbl.pack(pady=12)
        prog_bar = ttk.Progressbar(progress_win, length=280, maximum=n_selected)
        prog_bar.pack()
        self.root.update_idletasks()

        for gi, gname in enumerate(selected_group_names):
            prog_lbl.config(text=f"Processing {gname}…")
            prog_bar['value'] = gi
            self.root.update_idletasks()
            subject_list = list(results[gname]['subjects'].keys())
            mat, n_bouts = _epoch_spectrogram_for_subjects(subject_list)
            if mat is not None:
                group_matrices[gname] = mat
                group_bouts[gname]    = n_bouts

        progress_win.destroy()

        if not group_matrices:
            messagebox.showwarning("No Data",
                "No valid epochs found for any group.")
            return

        valid_groups = list(group_matrices.keys())
        n_valid = len(valid_groups)

        def _draw_panel(ax, times, freqs, coh_tf, title, cmap=None, vmin=0, vmax=1):
            cmap = cmap or parula
            pcm = ax.pcolormesh(times, freqs, coh_tf,
                                cmap=cmap, vmin=vmin, vmax=vmax, shading='auto')
            ax.set_yscale('log')
            ax.yaxis.set_major_formatter(mticker.FuncFormatter(lambda v, _: f'{v:g}'))
            ax.yaxis.set_minor_formatter(mticker.NullFormatter())
            ax.axvline(x=0, color='white', linestyle='--', linewidth=0.6, alpha=0.9)
            cb = ax.get_figure().colorbar(pcm, ax=ax, pad=0.02, fraction=0.046)
            cb.set_label('Coherence', fontsize=9)
            ax.set_xlabel('Time relative to onset (s)', fontsize=10)
            ax.set_ylabel('Hz', fontsize=10)
            ax.set_title(title, fontsize=10, fontweight='bold')
            ax.set_xlim(times[0], times[-1])
            ax.set_ylim(freqs[0], freqs[-1])

        # ── Select two groups for the contrast panel ──────────────────
        contrast_groups = {'A': None, 'B': None}
        if n_valid >= 2:
            sel_dlg = tk.Toplevel(self.root)
            sel_dlg.title("Group Contrast Selection")
            sel_dlg.geometry("340x220")
            sel_dlg.transient(self.root)
            sel_dlg.grab_set()

            ttk.Label(sel_dlg, text="Select two groups for difference image\n(Group A − Group B)\nBlue = A higher  |  Red = B higher",
                      font=('Segoe UI', 9), justify='center').pack(pady=(10, 6))

            var_A = tk.StringVar(value=valid_groups[0])
            var_B = tk.StringVar(value=valid_groups[1] if n_valid > 1 else valid_groups[0])

            row_a = ttk.Frame(sel_dlg)
            row_a.pack(anchor='w', padx=20, pady=2)
            ttk.Label(row_a, text="Group A:").pack(side='left')
            ttk.Combobox(row_a, textvariable=var_A, values=valid_groups,
                         state='readonly', width=18).pack(side='left', padx=4)

            row_b = ttk.Frame(sel_dlg)
            row_b.pack(anchor='w', padx=20, pady=2)
            ttk.Label(row_b, text="Group B:").pack(side='left')
            ttk.Combobox(row_b, textvariable=var_B, values=valid_groups,
                         state='readonly', width=18).pack(side='left', padx=4)

            def _ok_contrast():
                contrast_groups['A'] = var_A.get()
                contrast_groups['B'] = var_B.get()
                sel_dlg.destroy()

            btn_row = ttk.Frame(sel_dlg)
            btn_row.pack(pady=10)
            ttk.Button(btn_row, text="Plot", command=_ok_contrast).pack(side='left', padx=4)
            ttk.Button(btn_row, text="Skip contrast", command=sel_dlg.destroy).pack(side='left', padx=4)
            sel_dlg.wait_window()

        # ── Build figure ──────────────────────────────────────────────
        has_contrast = (contrast_groups['A'] and contrast_groups['B']
                        and contrast_groups['A'] != contrast_groups['B']
                        and contrast_groups['A'] in group_matrices
                        and contrast_groups['B'] in group_matrices)
        n_panels = n_valid + (1 if has_contrast else 0)
        ncols    = min(n_panels, 3)
        nrows    = int(np.ceil(n_panels / ncols))

        # Each panel: width proportional to time range, fixed height ~4
        time_span = pre_sec + post_sec
        panel_w = max(3.5, min(5.0, time_span * 0.25))
        panel_h = 4.0
        fig = Figure(figsize=(panel_w * ncols + 1.5, panel_h * nrows + 0.8), dpi=100)

        for pi, gname in enumerate(valid_groups):
            ax  = fig.add_subplot(nrows, ncols, pi + 1)
            n_s = len(results[gname]['subjects'])
            _draw_panel(ax, times, freqs, group_matrices[gname],
                        f"{gname}  (n={n_s} subj, {group_bouts[gname]} bouts)")

        if has_contrast:
            diff = group_matrices[contrast_groups['A']] - group_matrices[contrast_groups['B']]
            abs_max = np.nanmax(np.abs(diff))
            if abs_max < 1e-9:
                abs_max = 0.1
            ax_diff = fig.add_subplot(nrows, ncols, n_valid + 1)
            pcm_diff = ax_diff.pcolormesh(times, freqs, diff,
                                          cmap='RdBu_r',
                                          vmin=-abs_max, vmax=abs_max,
                                          shading='auto')
            ax_diff.set_yscale('log')
            ax_diff.yaxis.set_major_formatter(
                mticker.FuncFormatter(lambda v, _: f'{v:g}'))
            ax_diff.yaxis.set_minor_formatter(mticker.NullFormatter())
            ax_diff.axvline(x=0, color='black', linestyle='--', lw=0.6, alpha=0.7)
            ax_diff.axhline(y=0, color='none')  # prevents log-scale warning
            cb = fig.colorbar(pcm_diff, ax=ax_diff, pad=0.02, fraction=0.046)
            cb.set_label('Δ Coherence (A − B)', fontsize=9)
            ax_diff.set_xlabel('Time relative to onset (s)', fontsize=10)
            ax_diff.set_ylabel('Hz', fontsize=10)
            ax_diff.set_title(
                f"Contrast: {contrast_groups['A']} − {contrast_groups['B']}\n"
                f"Blue = A higher  |  Red = B higher",
                fontsize=10, fontweight='bold')
            ax_diff.set_xlim(times[0], times[-1])
            ax_diff.set_ylim(freqs[0], freqs[-1])

        fig.suptitle(
            f"BEG Peri-Event Spectrogram  |  {ch1} ↔ {ch2}  "
            f"|  Behavior: {behavior}",
            fontsize=11, fontweight='bold')
        fig.tight_layout(rect=[0, 0, 1, 0.95])

        win = tk.Toplevel(self.root)
        win.title("BEG Peri-Event Wavelet Coherence")
        win_w = min(1600, max(700, int((panel_w * ncols + 1.5) * 100 + 40)))
        win_h = min(1000, max(450, int((panel_h * nrows + 0.8) * 100 + 60)))
        win.geometry(f"{win_w}x{win_h}")
        cw = FigureCanvasTkAgg(fig, master=win)
        cw.draw()
        cw.get_tk_widget().pack(fill='both', expand=True)
        NavigationToolbar2Tk(cw, win).update()

    def export_beg_comparison(self):
        """Export per-subject pre/post/delta coherence per band and per frequency to CSV."""
        if not hasattr(self, 'beg_results') or not self.beg_results:
            messagebox.showwarning("No Data",
                "Run '▶ Run Bout-Epoch Group Comparison' first.")
            return

        filepath = filedialog.asksaveasfilename(
            defaultextension='.csv',
            filetypes=[('CSV files', '*.csv'), ('All files', '*.*')],
            title="Save Bout-Epoch Group Coherence")
        if not filepath:
            return

        bands = self._get_active_freq_bands()
        band_rows  = []
        freq_rows  = []

        for gname, gdata in self.beg_results.items():
            for subj, sdata in gdata['subjects'].items():
                # Band summary
                row = {
                    'Group': gname, 'Subject': subj,
                    'Behavior': gdata['behavior'],
                    'Ch1': gdata['ch1'], 'Ch2': gdata['ch2'],
                    'Method': gdata['method'],
                    'N_Bouts': sdata['n_bouts'],
                    'Pre_sec': gdata['pre_sec'],
                    'Post_sec': gdata['post_sec'],
                    'Mean_Pre_Coh_All':  round(float(np.nanmean(sdata['pre_coh_mean'])),  6),
                    'Mean_Post_Coh_All': round(float(np.nanmean(sdata['post_coh_mean'])), 6),
                    'Delta_Coh_All':     round(float(np.nanmean(sdata['post_coh_mean']) -
                                                     np.nanmean(sdata['pre_coh_mean'])), 6),
                }
                for b in bands:
                    pre_v  = self._band_mean_from_spectrum(sdata['pre_freqs'],  sdata['pre_coh_mean'],  b)
                    post_v = self._band_mean_from_spectrum(sdata['post_freqs'], sdata['post_coh_mean'], b)
                    row[f"Pre_{b['name']}_coh"]   = round(pre_v, 6)
                    row[f"Post_{b['name']}_coh"]  = round(post_v, 6)
                    row[f"Delta_{b['name']}_coh"] = round(post_v - pre_v, 6)
                band_rows.append(row)

                # Per-frequency
                for freq, pre_c, post_c in zip(sdata['pre_freqs'],
                                               sdata['pre_coh_mean'],
                                               sdata['post_coh_mean']):
                    freq_rows.append({
                        'Group': gname, 'Subject': subj,
                        'Behavior': gdata['behavior'],
                        'Frequency_Hz': round(float(freq), 6),
                        'Baseline_Coherence': round(float(pre_c),  6),
                        'PostOnset_Coherence': round(float(post_c), 6),
                        'Delta_Coherence':    round(float(post_c - pre_c), 6),
                    })

        band_path = filepath
        freq_path = filepath.replace('.csv', '_per_frequency.csv')
        pd.DataFrame(band_rows).to_csv(band_path, index=False)
        pd.DataFrame(freq_rows).to_csv(freq_path, index=False)
        self.log_message(f"Bout-epoch group data exported: {band_path}")
        messagebox.showinfo("Export Complete",
            f"Band summary:      {band_path}\nPer-frequency: {freq_path}")

