        # ── Sliding Coherence ─────────────────────────────────────────
        f2 = ttk.LabelFrame(sf, text='Sliding Coherence', padding=8)
        f2.pack(fill='x', padx=10, pady=5)
        vars_['sliding_win_sec']     = row(f2, 'Window duration (s)',  'sliding_win_sec',     0, '10 \u2013 120')
        vars_['sliding_step_sec']    = row(f2, 'Step size (s)',        'sliding_step_sec',    1, '1 \u2013 30')
        vars_['sliding_nperseg_sec'] = row(f2, 'Welch window (s)',     'sliding_nperseg_sec', 2, 'must be < window duration')

        # ── Morlet Wavelet Parameters ─────────────────────────────────
        f_morlet = ttk.LabelFrame(sf, text='Morlet Wavelet Parameters', padding=8)
        f_morlet.pack(fill='x', padx=10, pady=5)
