        vars_['rolling_step_sec'] = row(f3, 'Step size (s)',       'rolling_step_sec', 1, '0.5 \u2013 10')

        ttk.Label(f3, text='Method').grid(row=2, column=0, sticky='w', padx=8, pady=3)
        method_var = tk.StringVar(value=p['rolling_method'])
        ttk.Combobox(f3, textvariable=method_var,
                     values=['pearson', 'spearman'],
                     state='readonly', width=12).grid(row=2, column=1, sticky='w', padx=5, pady=3)
        vars_['rolling_method'] = method_var

        fisher_var = tk.BooleanVar(value=p['rolling_fisher_z'])
