        vars_['coh_ymin']  = row(f5, 'Coherence Y min',    'coh_ymin',  3)
        vars_['coh_ymax']  = row(f5, 'Coherence Y max',    'coh_ymax',  4)
        ttk.Separator(f5, orient='horizontal').grid(row=5, column=0, columnspan=3, sticky='ew', pady=4)
