    def create_system_tab(self):
        """Tab for checking system requirements and dependencies"""
        tab = ttk.Frame(self.notebook)
        self.notebook.add(tab, text="System Check")
        self.system_check_tab = tab  # keep reference for tab-title updates... !!
        
        # Title
        title_label = ttk.Label(tab, text="System Requirements Check", 
                               font=('Segoe UI', 14, 'bold'))
        title_label.pack(pady=10)
        
        # Checks frame
        checks_frame = ttk.LabelFrame(tab, text="Dependency Status", padding=20)
        checks_frame.pack(fill='both', expand=True, padx=20, pady=10)
        
        # Create grid for status indicators
        self.system_checks = {}
        dependencies = [
            ('Python', 'python'),
            ('pandas', 'pandas'),
            ('NumPy', 'numpy'),
            ('SciPy', 'scipy'),
            ('Matplotlib', 'matplotlib'),
            ('openpyxl', 'openpyxl'),
            ('tkinter', 'tkinter')
        ]
        
        for i, (display_name, module_name) in enumerate(dependencies):
            # Label
            ttk.Label(checks_frame, text=f"{display_name}:", 
                     font=('Segoe UI', 10)).grid(row=i, column=0, sticky='w', pady=5, padx=(0, 20))
            
            # Status label
            status_label = ttk.Label(checks_frame, text="Checking...", 
                                    foreground='gray', font=('Segoe UI', 10))
            status_label.grid(row=i, column=1, sticky='w', pady=5, padx=(0, 10))
            
            # Version label
            version_label = ttk.Label(checks_frame, text="", 
                                     foreground='blue', font=('Segoe UI', 9))
            version_label.grid(row=i, column=2, sticky='w', pady=5)
            
            self.system_checks[module_name] = {
                'status': status_label,
                'version': version_label,
                'name': display_name
            }
        
        # Buttons frame
        button_frame = ttk.Frame(tab)
        button_frame.pack(pady=20)
        
        ttk.Button(button_frame, text="Check All Dependencies", 
                  command=self.check_all_dependencies).pack(side='left', padx=5)
        ttk.Button(button_frame, text="Install Requirements", 
                  command=self.install_requirements).pack(side='left', padx=5)
        ttk.Button(button_frame, text="View Requirements.txt", 
                  command=self.view_requirements).pack(side='left', padx=5)

        # Application Update section
        update_frame = ttk.LabelFrame(tab, text="Application Updates", padding=10)
        update_frame.pack(fill='x', padx=20, pady=(0, 10))

        update_inner = ttk.Frame(update_frame)
        update_inner.pack(fill='x')

        ttk.Label(update_inner, text="Update Status:", font=('Segoe UI', 10)).pack(side='left', padx=(0, 10))
        self.update_status_label = ttk.Label(update_inner, text="Not checked",
                                             foreground='gray', font=('Segoe UI', 10))
        self.update_status_label.pack(side='left', padx=(0, 20))

        self.check_update_button = ttk.Button(update_inner, text="Check for Updates",
                                              command=self.check_for_updates)
        self.check_update_button.pack(side='left', padx=5)

        self.install_update_button = ttk.Button(update_inner, text="Install Update",
                                                command=self.perform_update, state='disabled')
        self.install_update_button.pack(side='left', padx=5)


        results_frame = ttk.LabelFrame(tab, text="Installation Log", padding=10)
        results_frame.pack(fill='both', expand=True, padx=20, pady=(0, 20))
        
        self.system_text = tk.Text(results_frame, height=8, font=('Consolas', 9))
        self.system_text.pack(fill='both', expand=True)
        sys_scrollbar = ttk.Scrollbar(results_frame, command=self.system_text.yview)
        sys_scrollbar.pack(side='right', fill='y')
        self.system_text.config(yscrollcommand=sys_scrollbar.set)
        
        # Auto-check on tab creation
        self.root.after(100, self.check_all_dependencies)
    
