    def browse_fpdata(self):
        filename = filedialog.askopenfilename(title="Select FPData File", 
                                             filetypes=[("CSV files", "*.csv"), ("All files", "*.*")])
        if filename:
            self.fpdata_path_var.set(filename)
            # Auto-detect subject ID from filename using configured patterns
            basename = os.path.basename(filename)
            fpdata_pattern = self.params.get('fpdata_pattern', 'FPData')
            fpdata_suffix = self.params.get('fpdata_suffix', '0.csv')
            
            # Try to extract subject ID
            subject_id = self.extract_subject_id(basename, fpdata_pattern, fpdata_suffix)
            if subject_id:
                self.subject_id_var.set(subject_id)
                
                # Try to find corresponding timestamp file using configured patterns
                folder = os.path.dirname(filename)
                timestamp_patterns = [p.strip().lower() for p in self.params.get('timestamp_pattern', 'ComputerTS|AnimalPosition').split('|')]
                timestamp_suffix = self.params.get('timestamp_suffix', '0.csv')
                
                for pattern in timestamp_patterns:
                    # Try different possible timestamp filenames
                    for separator in ['', '_', '-']:
                        ts_filename = f"{subject_id}{separator}{pattern}{timestamp_suffix}"
                        ts_path = os.path.join(folder, ts_filename)
                        if os.path.exists(ts_path):
                            self.computerts_path_var.set(ts_path)
                            return
                        # Also try with pattern capitalized different ways
                        for ts_file in os.listdir(folder):
                            if (ts_file.lower().startswith(subject_id.lower()) and 
                                pattern in ts_file.lower() and 
                                ts_file.endswith('.csv')):
                                self.computerts_path_var.set(os.path.join(folder, ts_file))
                                return
    
