        if show_g1:
            g1_means = [v.get('G1_mean', np.nan) for _, v in eucl_bins]
            ax.plot(distances, g1_means, 's-', label='G1', linewidth=2, markersize=6, color='green')

        ax.set_xlabel('Euclidean Distance from Center (cm)')
